const activeControllers = new Set<AbortController>();
let acceptingRequests = true;

export function setRequestAcceptance(accepting: boolean): void {
  acceptingRequests = accepting;
}

export function beginModelRequest(): AbortController {
  if (!acceptingRequests) throw new Error('镜渊已禁用，不再接受新请求');
  const controller = new AbortController();
  activeControllers.add(controller);
  return controller;
}

export function finishModelRequest(controller: AbortController): void {
  activeControllers.delete(controller);
}

export function abortActiveRequests(): void {
  for (const controller of activeControllers) controller.abort();
  activeControllers.clear();
}
