export type TaskKind = 'audit' | 'revision' | 'state' | 'smallSummary' | 'largeSummary';
export type ConnectionMode = 'current' | 'profile';

export interface TaskConnectionSettings {
  mode: ConnectionMode;
  /** Stable Connection Manager profile id. */
  profileId: string;
  /** Legacy/display-only profile name retained for migration. */
  profile: string;
}

export type AuditFailAction = 'mark' | 'hide' | 'revise';
export type RevisionFallbackAction = 'mark' | 'hide';

export interface MirrorAbyssSettings {
  enabled: boolean;
  autoState: boolean;
  showMessagePanel: boolean;
  showTopButton: boolean;
  auditEnabled: boolean;
  auditPrompt: string;
  auditFailAction: AuditFailAction;
  revisionPrompt: string;
  maxRevisionAttempts: number;
  stopOnRepeatedViolation: boolean;
  revisionFallbackAction: RevisionFallbackAction;
  autoSmallSummary: boolean;
  smallSummaryTurns: number;
  autoLargeSummary: boolean;
  largeSummaryCount: number;
  lorebookSync: boolean;
  autoCreateLorebook: boolean;
  lorebookName: string;
  vectorizeRows: boolean;
  latestContinuityConstant: boolean;
  lorebookLayout: 'semantic' | 'detailed';
  repairInvalidJsonOnce: boolean;
  requestTimeoutMs: number;
  connections: Record<TaskKind, TaskConnectionSettings>;
  ui: {
    activeTab: 'overview' | 'tables' | 'graph' | 'summaries' | 'audit' | 'sync' | 'settings' | 'diagnostics';
    activeTable: TableKey;
    graphScope: 'relations' | 'world';
    graphZoom: number;
  };
  migration: {
    legacyChecked: boolean;
  };
}

