import { currentChatKey, getChat, getMessage, getSettings } from '../core/context';
import { assertArtifactCommitCurrent, persistChatFor } from '../core/commit-guard';
import { toErrorMessage } from '../core/utils';
import { markStage } from '../domain/artifact';
import { applySedimentation } from '../domain/sedimentation';
import { normalizeSummary } from '../domain/summary';
import { decideSmallSummary } from '../domain/summary-policy';
import { attachArtifactToMessage } from '../domain/artifact';
import { generateStructuredTask } from '../llm/structured';
import { largeSummaryPrompt, largeSummarySystemPrompt, smallSummaryPrompt, smallSummarySystemPrompt } from '../prompts/summary';
import { getChatState, putArtifact, putChatState } from '../storage/repository';
import type { MessageArtifact, StateSnapshot, SummaryArtifact } from '../types';

function successfulArtifacts(): MessageArtifact[] {
  const chatKey = currentChatKey();
  return getChat()
    .filter((message) => !message?.is_user)
    .map((message) => message?.extra?.mirrorAbyssV11 as MessageArtifact | undefined)
    .filter((artifact): artifact is MessageArtifact => Boolean(
      artifact?.chatKey === chatKey
      && artifact.snapshot
      && artifact.stages.state.status === 'success',
    ));
}

function transcriptFor(artifacts: MessageArtifact[]): string {
  return artifacts.map((artifact) => {
    const packageValue = artifact.factPackage;
    if (!packageValue) {
      return `【回合 ${artifact.messageIndex + 1}】\n玩家：${artifact.playerText || '（空）'}\n正文：${artifact.assistantText}`;
    }
    const facts = packageValue.facts.map((fact) =>
      `- [${fact.confidence}] ${fact.type}/${fact.operation}｜${fact.title}：${fact.content}`,
    ).join('\n');
    return `【回合 ${artifact.messageIndex + 1}】\n事实摘要：${packageValue.turnSummary || '（无）'}\n标准化事实：\n${facts || '（无可沉降事实）'}`;
  }).join('\n\n');
}

function allConsumedKeys(summaries: SummaryArtifact[]): Set<string> {
  return new Set(summaries.flatMap((item) => item.sourceKeys));
}

export function pendingSmallSummaries(small: SummaryArtifact[], large: SummaryArtifact[]): SummaryArtifact[] {
  const consumed = new Set(large.flatMap((item) => item.sourceKeys));
  return small.filter((item) => !consumed.has(item.id));
}

export async function generateSmallSummary(artifact: MessageArtifact, force = false): Promise<SummaryArtifact | null> {
  const settings = getSettings();
  const chatState = await getChatState(artifact.chatKey);
  const consumed = allConsumedKeys(chatState.smallSummaries);
  const all = successfulArtifacts();
  const pending = all.filter((item) => !consumed.has(item.messageKey));
  const decision = decideSmallSummary(all, pending, settings.smallSummaryTurns);
  if (!force && !decision.shouldSummarize) return null;
  if (!pending.length) return null;
  const selected = force ? pending : pending.slice(0, decision.maxTurns);
  const latestSnapshot = selected.at(-1)?.snapshot as StateSnapshot;
  const parsed = await generateStructuredTask({
    task: 'smallSummary',
    systemPrompt: smallSummarySystemPrompt(),
    prompt: smallSummaryPrompt(transcriptFor(selected), latestSnapshot),
    structureDescription: '{"title":"...","summary":"...","keywords":["..."],"sedimentation":{"removeRowIds":["..."],"characterActivityUpdates":[{"rowId":"...","activity":"休眠|长期休眠|已归档","reason":"..."}],"notes":["..."]}}',
  });
  assertArtifactCommitCurrent(artifact);
  const summary = normalizeSummary(parsed, 'small', selected.map((item) => item.messageKey));
  if (!summary.summary) throw new Error('小总结模型返回空摘要');
  const previousSnapshot = artifact.snapshot ? structuredClone(artifact.snapshot) : undefined;
  const previousSummaries = [...chatState.smallSummaries];
  try {
    if (artifact.snapshot) artifact.snapshot = applySedimentation(artifact.snapshot, summary);
    const message = getMessage(artifact.messageIndex);
    if (message) attachArtifactToMessage(message, artifact);
    await persistChatFor(artifact.chatKey);
    chatState.smallSummaries.push(summary);
    await putChatState(chatState);
  } catch (error) {
    artifact.snapshot = previousSnapshot;
    chatState.smallSummaries = previousSummaries;
    try {
      assertArtifactCommitCurrent(artifact);
      const message = getMessage(artifact.messageIndex);
      if (message) attachArtifactToMessage(message, artifact);
      await persistChatFor(artifact.chatKey).catch(() => undefined);
    } catch {
      // Chat or source text changed; the stale rollback must not touch the new chat.
    }
    throw error;
  }
  return summary;
}

export async function generateLargeSummary(artifact: MessageArtifact, force = false): Promise<SummaryArtifact | null> {
  const settings = getSettings();
  const chatState = await getChatState(artifact.chatKey);
  const pending = pendingSmallSummaries(chatState.smallSummaries, chatState.largeSummaries);
  const threshold = Math.max(1, Number(settings.largeSummaryCount) || 6);
  if (!force && pending.length < threshold) return null;
  if (!pending.length) return null;
  const selected = force ? pending : pending.slice(0, threshold);
  const snapshot = artifact.snapshot;
  if (!snapshot) throw new Error('没有可用于大总结的状态表');
  const previousLarge = chatState.largeSummaries.at(-1);
  const parsed = await generateStructuredTask({
    task: 'largeSummary',
    systemPrompt: largeSummarySystemPrompt(),
    prompt: largeSummaryPrompt(selected, snapshot, previousLarge),
    structureDescription: '{"title":"...","summary":"...","keywords":["..."]}',
  });
  assertArtifactCommitCurrent(artifact);
  const summary = normalizeSummary(
    parsed,
    'large',
    selected.map((item) => item.id),
    previousLarge?.id,
  );
  if (!summary.summary) throw new Error('大总结模型返回空摘要');
  chatState.largeSummaries.push(summary);
  await putChatState(chatState);
  return summary;
}

export async function runSummaryStage(
  artifact: MessageArtifact,
  kind: 'small' | 'large',
  force = false,
): Promise<void> {
  const settings = getSettings();
  const enabled = kind === 'small' ? settings.autoSmallSummary : settings.autoLargeSummary;
  if (!enabled && !force) return;
  const preserveEarlierFailure = !force && artifact.stages.summary.status === 'failed';
  if (!preserveEarlierFailure) markStage(artifact, 'summary', 'running');
  await putArtifact(artifact);
  try {
    if (kind === 'small') await generateSmallSummary(artifact, force);
    else await generateLargeSummary(artifact, force);
    if (!preserveEarlierFailure) markStage(artifact, 'summary', 'success');
    await putArtifact(artifact);
  } catch (error) {
    if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error;
    const label = kind === 'small' ? '小总结' : '大总结';
    const previous = artifact.stages.summary.error;
    const current = `${label}失败：${toErrorMessage(error)}`;
    markStage(artifact, 'summary', 'failed', previous && previous !== current ? `${previous}；${current}` : current);
    await putArtifact(artifact);
    throw error;
  }
}

export async function maybeRunSummaries(artifact: MessageArtifact, forceSmall = false, forceLarge = false): Promise<void> {
  const errors: string[] = [];
  try {
    await runSummaryStage(artifact, 'small', forceSmall);
  } catch (error) {
    if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error;
    errors.push(`小总结：${toErrorMessage(error)}`);
  }
  try {
    await runSummaryStage(artifact, 'large', forceLarge);
  } catch (error) {
    if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error;
    errors.push(`大总结：${toErrorMessage(error)}`);
  }
  if (errors.length) {
    const combined = errors.join('；');
    markStage(artifact, 'summary', 'failed', combined);
    await putArtifact(artifact);
    throw new Error(combined);
  }
}
