import { stateSchemaDescription } from '../domain/snapshot';
import type { StateSnapshot } from '../types';

export function stateSystemPrompt(): string {
  return `你是“镜渊”事实提取与状态维护器。你先把本轮正文标准化为事实，再依据这些事实维护当前世界状态；不续写故事。

输出必须是可直接被 JSON.parse 解析的完整JSON对象，不要输出Markdown、解释或额外文字。
根节点必须包含 turnSummary、facts、snapshot。
snapshot 必须包含九个数组：focus、spacetime、characters、relationships、items、skills、events、regions、foundations。
每行允许字段：id、title、content、keywords、status；focus与characters还允许 lifecycle。

facts 中每条事实字段：
- id：稳定事实ID。
- type：focus、spacetime、character、relationship、item、skill、event、region、foundation、historical、trace。
- entityId：对应对象的稳定ID；同一对象沿用旧ID。
- title、content、status、keywords。
- operation：create、update、append、close、supersede。
- confidence：confirmed、recorded、reported、uncertain。

事实规则：
1. 只写本轮正文实际新增、改变、结束或确认的事实，不复制全部旧状态。
2. 玩家输入中的动作和对白可视为已声明行为；玩家预设的外部结果不能单独作为 confirmed。
3. 他人陈述、传闻和推测必须使用 reported 或 uncertain，不得升级为 confirmed。
4. historical 和 trace 只作为总结素材，不强制进入当前活跃状态表。
5. turnSummary 只概括本轮已发生事实，不续写、不评价。

维护规则：
1. 保留未受本轮影响、仍成立的状态。只有本轮明确改变的状态才更新。
2. 过程压缩为当前结果，不写流水账。未确认、冲突和进行中事项不得强行闭合。
3. 尽量保留上一份快照的稳定id；新增对象才创建新id。
4. snapshot 必须以 facts 和上一份状态表为依据；外部结果以AI正文与已有状态中的可观察事实为准。
5. source=manual或locked=true的玩家记录不得覆盖、删除或改写。
6. relationships 中每行 title 必须明确写出关系两端，优先使用“对象A ↔ 对象B”格式；content只写已显影的关系事实，status写关系当前状态。
7. characters 只为正式显影的人物建立独立行。仅被提及、没有进入可观察接触面的人物，先写在相关事件或人物内容中，不单独建行。
8. 已建立的正式人物不得仅因离场、长期未出现、被遗忘或死亡而删除。人物离开接触面只改变activity；死亡只改变existence；被遗忘只改变memory。
9. lifecycle字段固定为：
   - existence：存活、死亡已确认、存在未知、失踪、身份存疑、虚构或误认已确认、存在被抹除、未标注。
   - activity：当前在场、当前相关、离场但仍活跃、休眠、长期休眠、已归档、未标注。
   - memory：广泛记得、部分人物记得、仅记录留存、仅痕迹留存、无人可确认记得、记忆被篡改、记忆被抹除、未标注。
   - evidenceLevel：已确认、可靠记录、多方陈述、单方陈述、推测、未知。
   - evidence：支持上述判断的可验证依据。
   - returnConditions：人物可能重新进入接触面的现实条件，不代表一定回来。
   - returnBlockers：阻止回流的已确认条件；没有可靠证据时留空。
10. 不得因“很久没出现”推定死亡；他人陈述死亡只能按证据等级记录。死亡已确认的人物仍保留遗留关系、物品、流程和后果。
11. items：普通物品按所有者合并为“人物名｜物品与资源”；拥有独立身份、状态、因果或追踪价值的重要物品才单独一行。
12. skills：按人物或主体合并为“人物名｜技能与能力”，只记录已显影能力、条件、消耗和边界，不生成隐藏能力。
13. events中独立事件使用“事件｜名称”，制度或手续使用“流程｜名称”。小事件可留在人物或区域内容中，不必拆行。
14. foundations只保留长期承重设定；当前局势、人物变化和事件进展不得写入基础设定。

结构示例：
{"turnSummary":"本轮事实摘要","facts":[{"id":"fact_1","type":"event","entityId":"event_x","title":"事件名称","content":"可观察事实","status":"进行中","keywords":["关键词"],"operation":"update","confidence":"confirmed"}],"snapshot":${stateSchemaDescription()}}`;
}

export function stateUserPrompt(
  previous: StateSnapshot,
  playerText: string,
  assistantText: string,
  repair = false,
): string {
  return `【上一份状态表】
${JSON.stringify(previous, null, 2)}

【玩家本轮输入】
${playerText || '（空）'}

【AI本轮正文】
${assistantText}

输出标准化事实与更新后的完整状态快照。${repair ? '\n上一次输出无法解析；这次只输出合法JSON对象。' : ''}`;
}

function rowSchema(lifecycle = false): Record<string, any> {
  const properties: Record<string, any> = {
    id: { type: 'string' },
    title: { type: 'string' },
    content: { type: 'string' },
    keywords: { type: 'array', items: { type: 'string' } },
    status: { type: 'string' },
  };
  if (lifecycle) {
    properties.lifecycle = {
      type: 'object',
      properties: {
        existence: { type: 'string' },
        activity: { type: 'string' },
        memory: { type: 'string' },
        evidenceLevel: { type: 'string' },
        evidence: { type: 'string' },
        returnConditions: { type: 'array', items: { type: 'string' } },
        returnBlockers: { type: 'array', items: { type: 'string' } },
      },
      required: ['existence', 'activity', 'memory', 'evidenceLevel', 'evidence', 'returnConditions', 'returnBlockers'],
      additionalProperties: false,
    };
  }
  return {
    type: 'object',
    properties,
    required: ['id', 'title', 'content', 'keywords', 'status', ...(lifecycle ? ['lifecycle'] : [])],
    additionalProperties: false,
  };
}

export function stateJsonSchema(): Record<string, any> {
  const snapshotProperties = Object.fromEntries([
    ['focus', rowSchema(true)],
    ['spacetime', rowSchema()],
    ['characters', rowSchema(true)],
    ['relationships', rowSchema()],
    ['items', rowSchema()],
    ['skills', rowSchema()],
    ['events', rowSchema()],
    ['regions', rowSchema()],
    ['foundations', rowSchema()],
  ].map(([key, schema]) => [key, { type: 'array', items: schema }]));
  return {
    name: 'MirrorAbyssStateResult',
    description: '镜渊事实和完整状态表',
    strict: true,
    value: {
      type: 'object',
      properties: {
        turnSummary: { type: 'string' },
        facts: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              id: { type: 'string' },
              type: { type: 'string' },
              entityId: { type: 'string' },
              title: { type: 'string' },
              content: { type: 'string' },
              status: { type: 'string' },
              keywords: { type: 'array', items: { type: 'string' } },
              operation: { type: 'string' },
              confidence: { type: 'string' },
            },
            required: ['id', 'type', 'entityId', 'title', 'content', 'status', 'keywords', 'operation', 'confidence'],
            additionalProperties: false,
          },
        },
        snapshot: {
          type: 'object',
          properties: snapshotProperties,
          required: ['focus', 'spacetime', 'characters', 'relationships', 'items', 'skills', 'events', 'regions', 'foundations'],
          additionalProperties: false,
        },
      },
      required: ['turnSummary', 'facts', 'snapshot'],
      additionalProperties: false,
    },
  };
}
