import type { StateSnapshot, SummaryArtifact } from '../types';

export function smallSummarySystemPrompt(): string {
  return `你是镜渊阶段沉降结算器。只输出合法JSON对象，不续写故事，不把未确认事项写成事实。
输出字段：title、summary、keywords、sedimentation。
sedimentation包含：removeRowIds、characterActivityUpdates、notes。
你只提出安全沉降：
- removeRowIds只能选择已经结束、关闭、失效、被替代或已归档的spacetime/events/regions行id。
- 不得删除focus、characters、relationships、items、skills、foundations。
- 正式人物永不因离场、遗忘、死亡或长期未出现而删除。
- characterActivityUpdates只允许把“离场但仍活跃→休眠”“休眠→长期休眠”“长期休眠→已归档”，不得改变存在状态和记忆状态。
- 玩家手动或锁定记录不得删除、覆盖或降级。
- summary正文必须明确写入被沉降的事实、仍保留的未决事项和人物回流条件。`;
}

export function smallSummaryPrompt(transcript: string, snapshot: StateSnapshot): string {
  return `将以下回合压缩成“当前周期小总结”，承担阶段沉降，不是流水账。
重点保留：确定结果、不可逆变化、当前人物/关系/物品/技能/区域状态、仍在进行的流程、未决与冲突。
已经被最终结果替代的中间动作不展开。

【回合】
${transcript}

【当前状态表】
${JSON.stringify(snapshot, null, 2)}

只输出以下结构：
{"title":"...","summary":"...","keywords":["..."],"sedimentation":{"removeRowIds":["已结束状态行id"],"characterActivityUpdates":[{"rowId":"人物行id","activity":"休眠或长期休眠或已归档","reason":"依据"}],"notes":["沉降说明"]}}`;
}

export function largeSummarySystemPrompt(): string {
  return '你是镜渊长期沉降结算器。只输出合法JSON对象，字段为 title、summary、keywords。输出必须是累计长期快照，而不是只复述本批小总结。';
}

export function largeSummaryPrompt(
  summaries: SummaryArtifact[],
  snapshot: StateSnapshot,
  previousLarge?: SummaryArtifact,
): string {
  const source = summaries.map((item) => `【${item.title}】\n${item.summary}`).join('\n\n');
  const previous = previousLarge ? `【上一版长期沉降】\n${previousLarge.summary}\n\n` : '';
  return `把“上一版长期沉降”和本批小总结合并为一份新的累计长期沉降。
保留长期仍成立的人物、关系、区域、物品、技能、事件结果、不可逆后果与未决事项；删除已经失去意义的阶段过程。
人物死亡、失踪、被遗忘、身份存疑等必须保留证据等级和遗留因果，不得用长期未出现替代死亡判断。

${previous}【本批小总结】
${source}

【当前状态表】
${JSON.stringify(snapshot, null, 2)}

只输出：{"title":"...","summary":"...","keywords":["..."]}`;
}
