import { TABLE_KEYS, TABLE_LABELS, type TableKey } from '../constants';
import type {
  ActivityState,
  CharacterLifecycle,
  EvidenceLevel,
  ExistenceState,
  MemoryState,
  StateRow,
  StateSnapshot,
} from '../types';
import { makeId, nowIso, safeText } from '../core/utils';

const EXISTENCE_STATES = new Set<ExistenceState>([
  '存活', '死亡已确认', '存在未知', '失踪', '身份存疑', '虚构或误认已确认', '存在被抹除', '未标注', '不适用',
]);
const ACTIVITY_STATES = new Set<ActivityState>([
  '当前在场', '当前相关', '离场但仍活跃', '休眠', '长期休眠', '已归档', '未标注', '不适用',
]);
const MEMORY_STATES = new Set<MemoryState>([
  '广泛记得', '部分人物记得', '仅记录留存', '仅痕迹留存', '无人可确认记得', '记忆被篡改', '记忆被抹除', '未标注', '不适用',
]);
const EVIDENCE_LEVELS = new Set<EvidenceLevel>(['已确认', '可靠记录', '多方陈述', '单方陈述', '推测', '未知']);

export function emptySnapshot(): StateSnapshot {
  return Object.fromEntries(TABLE_KEYS.map((key) => [key, []])) as unknown as StateSnapshot;
}

export function normalizeKeywords(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => safeText(item, 80).trim()).filter(Boolean))].slice(0, 16);
}

function normalizeStringList(value: unknown, limit = 12): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => safeText(item, 240).trim()).filter(Boolean))].slice(0, limit);
}

function enumValue<T extends string>(value: unknown, allowed: Set<T>, fallback: T): T {
  const text = safeText(value, 80).trim() as T;
  return allowed.has(text) ? text : fallback;
}

export function defaultLifecycle(): CharacterLifecycle {
  return {
    existence: '未标注',
    activity: '未标注',
    memory: '未标注',
    evidenceLevel: '未知',
    evidence: '',
    returnConditions: [],
    returnBlockers: [],
  };
}

export function normalizeLifecycle(value: unknown, previous?: CharacterLifecycle): CharacterLifecycle {
  const source = value && typeof value === 'object' ? (value as Record<string, unknown>) : {};
  const base = previous ?? defaultLifecycle();
  return {
    existence: enumValue(source.existence ?? base.existence, EXISTENCE_STATES, base.existence),
    activity: enumValue(source.activity ?? base.activity, ACTIVITY_STATES, base.activity),
    memory: enumValue(source.memory ?? base.memory, MEMORY_STATES, base.memory),
    evidenceLevel: enumValue(source.evidenceLevel ?? base.evidenceLevel, EVIDENCE_LEVELS, base.evidenceLevel),
    evidence: safeText(source.evidence ?? base.evidence, 4000).trim(),
    returnConditions: normalizeStringList(source.returnConditions ?? base.returnConditions),
    returnBlockers: normalizeStringList(source.returnBlockers ?? base.returnBlockers),
  };
}

export function normalizeRow(value: unknown, tableKey: TableKey, index: number, previous?: StateRow): StateRow {
  const source = value && typeof value === 'object' ? (value as Record<string, unknown>) : {};
  const now = nowIso();
  const id = safeText(source.id || previous?.id || makeId(tableKey), 160).trim() || makeId(tableKey);
  const manual = source.source === 'manual' || previous?.source === 'manual';
  const supportsLifecycle = tableKey === 'characters' || tableKey === 'focus';
  const lifecycleInput = source.lifecycle ?? previous?.lifecycle;
  return {
    id,
    title: safeText(source.title || source.name || previous?.title || `${TABLE_LABELS[tableKey]} ${index + 1}`, 240).trim(),
    content: safeText(source.content || source.summary || previous?.content || '', 12000).trim(),
    keywords: normalizeKeywords(source.keywords ?? previous?.keywords ?? []),
    status: safeText(source.status || previous?.status || 'active', 120).trim() || 'active',
    source: manual ? 'manual' : 'auto',
    locked: Boolean(source.locked ?? previous?.locked ?? manual),
    lifecycle: supportsLifecycle && lifecycleInput ? normalizeLifecycle(lifecycleInput, previous?.lifecycle) : undefined,
    updatedAt: safeText(source.updatedAt || previous?.updatedAt || now, 80) || now,
  };
}

export function normalizeSnapshot(value: unknown, previousSnapshot?: StateSnapshot): StateSnapshot {
  const source = value && typeof value === 'object' ? (value as Record<string, unknown>) : {};
  const output = emptySnapshot();
  for (const key of TABLE_KEYS) {
    const rows = Array.isArray(source[key]) ? (source[key] as unknown[]) : [];
    const previousMap = new Map((previousSnapshot?.[key] ?? []).map((row) => [row.id, row]));
    const used = new Set<string>();
    output[key] = rows.map((row, index) => {
      const rawId = row && typeof row === 'object' ? safeText((row as any).id, 160) : '';
      const normalized = normalizeRow(row, key, index, rawId ? previousMap.get(rawId) : undefined);
      if (used.has(normalized.id)) normalized.id = makeId(key);
      used.add(normalized.id);
      return normalized;
    });
  }
  return output;
}

function identityTitle(value: string): string {
  return String(value || '').toLowerCase().replace(/[\s·•._—–\-|｜:：()（）【】\[\]]+/g, '');
}

export function preservePersistentCharacters(previous: StateSnapshot, next: StateSnapshot): StateSnapshot {
  const byId = new Map((next.characters ?? []).map((row) => [row.id, row]));
  const byTitle = new Map((next.characters ?? []).map((row) => [identityTitle(row.title), row]));
  for (const oldRow of previous.characters ?? []) {
    if (byId.has(oldRow.id)) continue;
    const titleMatch = byTitle.get(identityTitle(oldRow.title));
    if (titleMatch) {
      titleMatch.id = oldRow.id;
      if (oldRow.source === 'manual' || oldRow.locked) {
        Object.assign(titleMatch, { ...oldRow, id: oldRow.id });
      } else if (!titleMatch.lifecycle && oldRow.lifecycle) {
        titleMatch.lifecycle = { ...oldRow.lifecycle };
      }
      byId.set(oldRow.id, titleMatch);
      continue;
    }
    const restored = { ...oldRow, lifecycle: oldRow.lifecycle ? { ...oldRow.lifecycle } : undefined };
    next.characters.push(restored);
    byId.set(restored.id, restored);
    byTitle.set(identityTitle(restored.title), restored);
  }
  const seenTitles = new Set<string>();
  next.characters = next.characters.filter((row) => {
    const key = identityTitle(row.title);
    if (!key || !seenTitles.has(key)) {
      if (key) seenTitles.add(key);
      return true;
    }
    return false;
  });
  return next;
}

export function snapshotRowCount(snapshot?: StateSnapshot): number {
  if (!snapshot) return 0;
  return TABLE_KEYS.reduce((sum, key) => sum + (snapshot[key]?.length ?? 0), 0);
}

export function upsertManualRow(snapshot: StateSnapshot, tableKey: TableKey, row: Partial<StateRow> & { id?: string }): StateSnapshot {
  const next = normalizeSnapshot(snapshot, snapshot);
  const index = next[tableKey].findIndex((item) => item.id === row.id);
  const normalized = normalizeRow({ ...row, source: 'manual', locked: row.locked ?? true, updatedAt: nowIso() }, tableKey, index >= 0 ? index : next[tableKey].length, index >= 0 ? next[tableKey][index] : undefined);
  if (index >= 0) next[tableKey][index] = normalized;
  else next[tableKey].push(normalized);
  return next;
}

export function deleteRow(snapshot: StateSnapshot, tableKey: TableKey, rowId: string): StateSnapshot {
  const next = normalizeSnapshot(snapshot, snapshot);
  next[tableKey] = next[tableKey].filter((row) => row.id !== rowId);
  return next;
}

