import type { QueueTask } from '../types';
import { makeId, nowIso, toErrorMessage } from '../core/utils';

export interface TaskRunGuard {
  readonly generation: number;
  assertCurrent(): void;
}

interface RunOptions {
  priority?: number;
  chatKey?: string;
}

interface PendingJob<T = unknown> {
  task: QueueTask & Record<string, any>;
  work: (guard: TaskRunGuard) => Promise<T>;
  generation: number;
  sequence: number;
  priority: number;
  chatKey?: string;
  promise: Promise<T>;
  resolve: (value: T | PromiseLike<T>) => void;
  reject: (reason?: unknown) => void;
}

function cancelledError(message: string): Error {
  const error = new Error(message);
  error.name = 'AbortError';
  return error;
}

function elapsed(startedAt?: number, finishedAt = Date.now()): number | undefined {
  return startedAt === undefined ? undefined : Math.max(0, finishedAt - startedAt);
}

const DEFAULT_PRIORITIES: Record<string, number> = {
  audit: 100,
  revision: 100,
  state: 90,
  manual: 70,
  sync: 40,
  smallSummary: 30,
  largeSummary: 10,
};

export class TaskQueue {
  private static readonly MAX_TASKS = 200;
  private inFlight = new Map<string, Promise<unknown>>();
  private tasks = new Map<string, QueueTask & Record<string, any>>();
  private listeners = new Set<() => void>();
  private accepting = true;
  private generation = 0;
  private sequence = 0;
  private pending: PendingJob[] = [];
  private active: PendingJob | null = null;
  private idleWaiters = new Set<() => void>();

  setAccepting(accepting: boolean): void {
    if (this.accepting && !accepting) {
      this.generation += 1;
      this.cancelPending(() => true, '镜渊已禁用，排队任务已取消');
    }
    this.accepting = accepting;
    if (accepting) this.pump();
  }

  private isTerminal(task: QueueTask & Record<string, any>): boolean {
    return !['running', 'queued'].includes(String(task.state));
  }

  private pruneTasks(): void {
    while (this.tasks.size > TaskQueue.MAX_TASKS) {
      const removable = [...this.tasks.entries()].find(([, task]) => this.isTerminal(task));
      if (!removable) break;
      this.tasks.delete(removable[0]);
    }
  }

  subscribe(listener: () => void): () => void {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  }

  private notify(): void {
    for (const listener of this.listeners) {
      try {
        listener();
      } catch (error) {
        console.warn('[MirrorAbyss] task listener failed', error);
      }
    }
  }

  list(): QueueTask[] {
    return [...this.tasks.values()].sort((a, b) => String(b.createdAt).localeCompare(String(a.createdAt)));
  }

  has(key: string): boolean {
    return this.inFlight.has(key);
  }

  clearHistory(): void {
    for (const [id, task] of this.tasks) {
      if (this.isTerminal(task)) this.tasks.delete(id);
    }
    this.notify();
  }

  resetRuntime(): void {
    this.generation += 1;
    this.cancelPending(() => true, '镜渊运行环境已重置，排队任务已取消');
    this.clearHistory();
    this.notify();
  }

  private resolveIdle(): void {
    if (this.active || this.pending.length) return;
    for (const resolve of this.idleWaiters) resolve();
    this.idleWaiters.clear();
  }

  async whenIdle(): Promise<void> {
    if (!this.active && !this.pending.length) return;
    await new Promise<void>((resolve) => this.idleWaiters.add(resolve));
  }

  cancelPendingByChatKey(chatKey: string, reason = '聊天已切换，旧聊天排队任务已取消'): number {
    return this.cancelPending((job) => job.chatKey === chatKey, reason);
  }

  cancelPendingOutsideChat(chatKey: string, reason = '聊天已切换，旧聊天排队任务已取消'): number {
    return this.cancelPending((job) => Boolean(job.chatKey && job.chatKey !== chatKey), reason);
  }

  cancelPendingDerivedByChatKey(chatKey: string, reason = '已有更新的正文状态，旧派生任务已取消'): number {
    return this.cancelPending(
      (job) => job.chatKey === chatKey && String(job.task.key).includes(':derived:'),
      reason,
    );
  }

  private cancelPending(predicate: (job: PendingJob) => boolean, reason: string): number {
    const remaining: PendingJob[] = [];
    let cancelled = 0;
    const now = Date.now();
    for (const job of this.pending) {
      if (!predicate(job)) {
        remaining.push(job);
        continue;
      }
      cancelled += 1;
      job.task.state = 'cancelled';
      job.task.error = reason;
      job.task.finishedAt = nowIso();
      job.task.queueWaitMs = elapsed(job.task.createdAtMs, now);
      job.task.totalMs = elapsed(job.task.createdAtMs, now);
      if (this.inFlight.get(job.task.key) === job.promise) this.inFlight.delete(job.task.key);
      job.reject(cancelledError(reason));
    }
    this.pending = remaining;
    if (cancelled) {
      this.pruneTasks();
      this.notify();
    }
    this.resolveIdle();
    return cancelled;
  }

  private selectNext(): PendingJob | null {
    if (!this.pending.length) return null;
    let selectedIndex = 0;
    for (let index = 1; index < this.pending.length; index += 1) {
      const candidate = this.pending[index];
      const selected = this.pending[selectedIndex];
      if (candidate.priority > selected.priority || (
        candidate.priority === selected.priority && candidate.sequence < selected.sequence
      )) {
        selectedIndex = index;
      }
    }
    return this.pending.splice(selectedIndex, 1)[0] ?? null;
  }

  private pump(): void {
    if (this.active || !this.accepting) {
      this.resolveIdle();
      return;
    }
    const job = this.selectNext();
    if (!job) {
      this.resolveIdle();
      return;
    }
    this.active = job;
    const task = job.task;
    const startedMs = Date.now();
    task.state = 'running';
    task.startedAt = nowIso();
    task.startedAtMs = startedMs;
    task.queueWaitMs = elapsed(task.createdAtMs, startedMs);
    this.notify();

    const guard: TaskRunGuard = {
      generation: job.generation,
      assertCurrent: () => {
        if (!this.accepting || job.generation !== this.generation) {
          throw cancelledError('镜渊生命周期已变化，旧任务结果不再提交');
        }
      },
    };

    void Promise.resolve()
      .then(async () => {
        guard.assertCurrent();
        const result = await job.work(guard);
        guard.assertCurrent();
        return result;
      })
      .then((result) => {
        task.state = 'success';
        job.resolve(result);
      })
      .catch((error) => {
        const cancelled = error instanceof Error && error.name === 'AbortError';
        task.state = cancelled ? 'cancelled' : 'failed';
        task.error = toErrorMessage(error);
        job.reject(error);
      })
      .finally(() => {
        const finishedMs = Date.now();
        task.finishedAt = nowIso();
        task.runMs = elapsed(startedMs, finishedMs);
        task.totalMs = elapsed(task.createdAtMs, finishedMs);
        if (this.inFlight.get(task.key) === job.promise) this.inFlight.delete(task.key);
        if (this.active === job) this.active = null;
        this.pruneTasks();
        this.notify();
        this.pump();
      });
  }

  run<T>(
    key: string,
    label: string,
    kind: QueueTask['kind'],
    work: (guard: TaskRunGuard) => Promise<T>,
    options: RunOptions = {},
  ): Promise<T> {
    if (!this.accepting) return Promise.reject(cancelledError('镜渊已禁用，不再接受新任务'));
    const existing = this.inFlight.get(key);
    if (existing) return existing as Promise<T>;

    const createdMs = Date.now();
    const priority = Number.isFinite(options.priority)
      ? Number(options.priority)
      : (DEFAULT_PRIORITIES[String(kind)] ?? 50);
    const task = {
      id: makeId('task'),
      key,
      label,
      kind,
      state: 'queued',
      createdAt: nowIso(),
      createdAtMs: createdMs,
      priority,
      chatKey: options.chatKey,
    } as QueueTask & Record<string, any>;
    this.tasks.set(task.id, task);

    let resolve!: (value: T | PromiseLike<T>) => void;
    let reject!: (reason?: unknown) => void;
    const promise = new Promise<T>((resolveValue, rejectValue) => {
      resolve = resolveValue;
      reject = rejectValue;
    });
    const job: PendingJob<T> = {
      task,
      work,
      generation: this.generation,
      sequence: this.sequence += 1,
      priority,
      chatKey: options.chatKey,
      promise,
      resolve,
      reject,
    };
    this.pending.push(job as PendingJob);
    this.inFlight.set(key, promise);
    this.pruneTasks();
    this.notify();
    this.pump();
    return promise;
  }
}

export const taskQueue = new TaskQueue();
