import { currentChatKey, getContext, getMessage, messageFingerprint } from './context';
import type { MessageArtifact } from '../types';

const historyRevisions = new Map<string, number>();
const artifactHistoryRevisions = new WeakMap<MessageArtifact, number>();
const artifactTaskGuards = new WeakMap<MessageArtifact, { assertCurrent(): void }>();

export class CommitRejectedError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'CommitRejectedError';
  }
}


export function assertChatCommitCurrent(chatKey: string, message = '聊天已切换，本次结果不再写入'): void {
  if (currentChatKey() !== chatKey) {
    throw new CommitRejectedError(message);
  }
}

export async function persistChatFor(chatKey: string): Promise<void> {
  assertChatCommitCurrent(chatKey);
  const context = getContext();
  assertChatCommitCurrent(chatKey);
  if (typeof context.saveChat === 'function') {
    await context.saveChat.call(context);
  } else if (typeof context.saveChatConditional === 'function') {
    await context.saveChatConditional.call(context);
  }
  assertChatCommitCurrent(chatKey);
}

export async function persistMetadataFor(chatKey: string): Promise<void> {
  assertChatCommitCurrent(chatKey, '聊天已切换，本次元数据不再写入');
  const context = getContext();
  assertChatCommitCurrent(chatKey, '聊天已切换，本次元数据不再写入');
  if (typeof context.saveMetadata === 'function') {
    await context.saveMetadata.call(context);
  } else {
    context.saveMetadataDebounced?.call(context);
  }
  assertChatCommitCurrent(chatKey, '聊天已切换，本次元数据不再写入');
}

export function currentHistoryRevision(chatKey: string): number {
  return historyRevisions.get(chatKey) ?? 0;
}

export function invalidateHistoryRevision(chatKey: string): number {
  const next = currentHistoryRevision(chatKey) + 1;
  historyRevisions.set(chatKey, next);
  return next;
}

export function assertHistoryRevisionCurrent(chatKey: string, expectedRevision: number): void {
  if (currentHistoryRevision(chatKey) !== expectedRevision) {
    throw new CommitRejectedError('历史消息已经变化，本次旧任务结果不再写入');
  }
}

export function bindArtifactHistoryRevision(artifact: MessageArtifact, revision: number): void {
  artifactHistoryRevisions.set(artifact, revision);
}

export function unbindArtifactHistoryRevision(artifact: MessageArtifact, revision?: number): void {
  if (revision === undefined || artifactHistoryRevisions.get(artifact) === revision) {
    artifactHistoryRevisions.delete(artifact);
  }
}


export function bindArtifactTaskGuard(artifact: MessageArtifact, guard: { assertCurrent(): void }): void {
  artifactTaskGuards.set(artifact, guard);
}

export function unbindArtifactTaskGuard(artifact: MessageArtifact, guard?: { assertCurrent(): void }): void {
  if (!guard || artifactTaskGuards.get(artifact) === guard) artifactTaskGuards.delete(artifact);
}

export function assertArtifactCommitCurrent(artifact: MessageArtifact): void {
  artifactTaskGuards.get(artifact)?.assertCurrent();
  const expectedRevision = artifactHistoryRevisions.get(artifact);
  if (expectedRevision !== undefined) {
    assertHistoryRevisionCurrent(artifact.chatKey, expectedRevision);
  }
  assertChatCommitCurrent(artifact.chatKey);
  const message = getMessage(artifact.messageIndex);
  if (!message || message.is_user) {
    throw new CommitRejectedError('原AI正文已不存在，请重新整理');
  }
  if (messageFingerprint(artifact.messageIndex) !== artifact.sourceFingerprint) {
    throw new CommitRejectedError('正文已经变化，请重新整理');
  }
}
