import type { CharacterActivityUpdate, SedimentationPlan, SummaryArtifact } from '../types';
import { makeId, nowIso, safeText } from '../core/utils';

function stringList(value: unknown, limit = 40, itemLimit = 300): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => safeText(item, itemLimit).trim()).filter(Boolean))].slice(0, limit);
}

function normalizeActivityUpdates(value: unknown): CharacterActivityUpdate[] {
  if (!Array.isArray(value)) return [];
  const allowed = new Set(['休眠', '长期休眠', '已归档']);
  return value
    .map((item) => item && typeof item === 'object' ? item as Record<string, unknown> : {})
    .map((item) => ({
      rowId: safeText(item.rowId, 160).trim(),
      activity: safeText(item.activity, 40).trim() as CharacterActivityUpdate['activity'],
      reason: safeText(item.reason, 500).trim(),
    }))
    .filter((item) => item.rowId && allowed.has(item.activity))
    .slice(0, 30);
}

function normalizeSedimentation(value: unknown): SedimentationPlan | undefined {
  if (!value || typeof value !== 'object') return undefined;
  const source = value as Record<string, unknown>;
  return {
    removeRowIds: stringList(source.removeRowIds, 50, 160),
    characterActivityUpdates: normalizeActivityUpdates(source.characterActivityUpdates),
    notes: stringList(source.notes, 30, 500),
  };
}

export function normalizeSummary(
  value: Record<string, any>,
  kind: 'small' | 'large',
  sourceKeys: string[],
  previousLargeSummaryId?: string,
): SummaryArtifact {
  return {
    id: makeId(kind),
    kind,
    title: safeText(value.title || (kind === 'small' ? '阶段沉降' : '长期沉降'), 240).trim(),
    summary: safeText(value.summary || '', 30000).trim(),
    keywords: Array.isArray(value.keywords)
      ? [...new Set(value.keywords.map((item: unknown) => safeText(item, 80).trim()).filter(Boolean))].slice(0, 24)
      : [],
    sourceKeys,
    createdAt: nowIso(),
    sedimentation: kind === 'small' ? normalizeSedimentation(value.sedimentation) : undefined,
    previousLargeSummaryId: kind === 'large' ? previousLargeSummaryId : undefined,
  };
}
